{
  "sourceId": "erp-system",
  "eventType": "invoice.generated",
  "name": "ERP Invoice Generated",
  "description": "Mapping with JSON Schema validation for ERP invoice events",
  "fieldMappings": {
    "invoiceId": "invoice_number",
    "customerId": "customer.code",
    "email": "customer.email_address",
    "amount": "total_amount",
    "currency": "currency_code",
    "dueDate": "payment.due_date"
  },
  "timestampField": "created_timestamp",
  "timestampFormat": "epoch_ms",
  "sourceEventIdField": "invoice_number",
  "validationSchema": {
    "type": "object",
    "required": ["invoice_number", "customer", "total_amount"],
    "properties": {
      "invoice_number": { "type": "string" },
      "customer": {
        "type": "object",
        "required": ["code", "email_address"],
        "properties": {
          "code": { "type": "string" },
          "email_address": { "type": "string", "format": "email" }
        }
      },
      "total_amount": { "type": "number", "minimum": 0 }
    }
  },
  "priority": "normal",
  "createdBy": "postman-tester"
}
